+
+        // Should miss now
+        let decision = middleware.on_request(&ctx, &request).unwrap();
+        assert!(matches!(decision, MiddlewareDecision::Continue));
+    }
+
+    #[test]
+    fn test_cache_stats_hit_rate() {
