+
+    #[test]
+    fn test_rate_limiting_middleware_per_client() {
+        let middleware = RateLimitingMiddleware::new(10.0)
+            .burst_capacity(1)
+            .client_id_extractor(|_ctx, req| Some(req.method.clone()));
+        let ctx = test_context();
